	goodsCartList:[],
	goodsGuessList:[],
	ongoodsGuessList:[],
	checkedGoods:[],
	allGoodsListId:[],
	checkedShop:[],
	shipping_fee:'',
	checkoutInfo:'',
	listShow:[],
	cartCheckedVlaue:[],
	pay_list:[],
	pay_id:'',
	doneinfo:'',
